import{_ as e,o as t,c as s,ae as i}from"./chunks/framework.BEtfQoF7.js";const u=JSON.parse('{"title":"Claude Code 세션 팀 오케스트레이션","description":"여러 Claude Code 인스턴스를 팀으로 조율하여 공유 작업, 에이전트 간 메시징, 중앙 집중식 관리를 수행하는 방법을 알아봅니다.","frontmatter":{"title":"Claude Code 세션 팀 오케스트레이션","description":"여러 Claude Code 인스턴스를 팀으로 조율하여 공유 작업, 에이전트 간 메시징, 중앙 집중식 관리를 수행하는 방법을 알아봅니다."},"headers":[],"relativePath":"agent-teams.md","filePath":"agent-teams.md","lastUpdated":1776155129000}'),o={name:"agent-teams.md"};function n(l,a,r,d,p,h){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="claude-code-세션-팀-오케스트레이션" tabindex="-1">Claude Code 세션 팀 오케스트레이션 <a class="header-anchor" href="#claude-code-세션-팀-오케스트레이션" aria-label="Permalink to &quot;Claude Code 세션 팀 오케스트레이션&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>에이전트 팀은 실험적 기능이며 기본적으로 비활성화되어 있습니다. <a href="/claude-code-docs-ko/settings.html">settings.json</a> 또는 환경 변수에 <code>CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS</code>를 추가하여 활성화할 수 있습니다. 에이전트 팀에는 세션 재개, 작업 조율, 종료 동작과 관련된 <a href="#limitations">알려진 제한 사항</a>이 있습니다.</p></div><p>에이전트 팀을 사용하면 여러 Claude Code 인스턴스가 함께 작업하도록 조율할 수 있습니다. 하나의 세션이 팀 리더 역할을 하여 작업을 조율하고, 업무를 할당하며, 결과를 종합합니다. 팀원들은 각자 독립된 컨텍스트 윈도우에서 독립적으로 작업하며, 서로 직접 통신합니다.</p><p>메인 에이전트에게만 결과를 보고할 수 있는 <a href="/claude-code-docs-ko/sub-agents.html">서브에이전트</a>와 달리, 에이전트 팀에서는 리더를 거치지 않고 개별 팀원과 직접 상호작용할 수도 있습니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>에이전트 팀은 Claude Code v2.1.32 이상이 필요합니다. <code>claude --version</code>으로 버전을 확인하세요.</p></div><p>이 페이지에서 다루는 내용:</p><ul><li><a href="#when-to-use-agent-teams">에이전트 팀을 사용할 때</a> - 최적의 사용 사례와 서브에이전트와의 비교</li><li><a href="#start-your-first-agent-team">팀 시작하기</a></li><li><a href="#control-your-agent-team">팀원 제어하기</a> - 디스플레이 모드, 작업 할당, 위임</li><li><a href="#best-practices">병렬 작업 모범 사례</a></li></ul><h2 id="when-to-use-agent-teams" tabindex="-1">에이전트 팀을 사용할 때 <a class="header-anchor" href="#when-to-use-agent-teams" aria-label="Permalink to &quot;에이전트 팀을 사용할 때 {#when-to-use-agent-teams}&quot;">​</a></h2><p>에이전트 팀은 병렬 탐색이 실질적인 가치를 더하는 작업에 가장 효과적입니다. 전체 시나리오는 <a href="#use-case-examples">사용 사례 예시</a>를 참조하세요. 가장 적합한 사용 사례는 다음과 같습니다:</p><ul><li><strong>연구 및 리뷰</strong>: 여러 팀원이 문제의 서로 다른 측면을 동시에 조사한 후, 서로의 발견 사항을 공유하고 검증할 수 있습니다</li><li><strong>새로운 모듈이나 기능</strong>: 팀원들이 각각 별도의 부분을 담당하여 서로 간섭하지 않습니다</li><li><strong>경쟁 가설을 통한 디버깅</strong>: 팀원들이 서로 다른 이론을 병렬로 테스트하여 더 빠르게 답을 찾습니다</li><li><strong>크로스 레이어 조율</strong>: 프론트엔드, 백엔드, 테스트에 걸친 변경 사항을 각각 다른 팀원이 담당합니다</li></ul><p>에이전트 팀은 조율 오버헤드가 추가되며 단일 세션보다 훨씬 더 많은 토큰을 사용합니다. 팀원들이 독립적으로 작업할 수 있을 때 가장 효과적입니다. 순차적 작업, 동일 파일 편집, 많은 의존성이 있는 작업의 경우 단일 세션이나 <a href="/claude-code-docs-ko/sub-agents.html">서브에이전트</a>가 더 효과적입니다.</p><h3 id="compare-with-subagents" tabindex="-1">서브에이전트와 비교 <a class="header-anchor" href="#compare-with-subagents" aria-label="Permalink to &quot;서브에이전트와 비교 {#compare-with-subagents}&quot;">​</a></h3><p>에이전트 팀과 <a href="/claude-code-docs-ko/sub-agents.html">서브에이전트</a> 모두 작업을 병렬화할 수 있지만, 작동 방식이 다릅니다. 작업자들이 서로 통신해야 하는지 여부에 따라 선택하세요:</p><p><img src="https://mintcdn.com/claude-code/nsvRFSDNfpSU5nT7/images/subagents-vs-agent-teams-light.png?fit=max&amp;auto=format&amp;n=nsvRFSDNfpSU5nT7&amp;q=85&amp;s=2f8db9b4f3705dd3ab931fbe2d96e42a" alt="서브에이전트와 에이전트 팀 아키텍처를 비교하는 다이어그램. 서브에이전트는 메인 에이전트에 의해 생성되어 작업을 수행하고 결과를 보고합니다. 에이전트 팀은 공유 작업 목록을 통해 조율하며, 팀원들이 서로 직접 통신합니다."></p><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">서브에이전트</th><th style="text-align:left;">에이전트 팀</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>컨텍스트</strong></td><td style="text-align:left;">자체 컨텍스트 윈도우; 결과가 호출자에게 반환됨</td><td style="text-align:left;">자체 컨텍스트 윈도우; 완전히 독립적</td></tr><tr><td style="text-align:left;"><strong>통신</strong></td><td style="text-align:left;">메인 에이전트에게만 결과를 보고</td><td style="text-align:left;">팀원들이 서로 직접 메시지를 주고받음</td></tr><tr><td style="text-align:left;"><strong>조율</strong></td><td style="text-align:left;">메인 에이전트가 모든 작업을 관리</td><td style="text-align:left;">공유 작업 목록으로 자체 조율</td></tr><tr><td style="text-align:left;"><strong>적합한 용도</strong></td><td style="text-align:left;">결과만 중요한 집중된 작업</td><td style="text-align:left;">토론과 협업이 필요한 복잡한 작업</td></tr><tr><td style="text-align:left;"><strong>토큰 비용</strong></td><td style="text-align:left;">낮음: 결과가 메인 컨텍스트로 요약됨</td><td style="text-align:left;">높음: 각 팀원이 별도의 Claude 인스턴스</td></tr></tbody></table><p>빠르고 집중된 작업자가 결과를 보고하면 되는 경우 서브에이전트를 사용하세요. 팀원들이 발견 사항을 공유하고, 서로의 의견에 이의를 제기하며, 자체적으로 조율해야 하는 경우 에이전트 팀을 사용하세요.</p><h2 id="enable-agent-teams" tabindex="-1">에이전트 팀 활성화 <a class="header-anchor" href="#enable-agent-teams" aria-label="Permalink to &quot;에이전트 팀 활성화 {#enable-agent-teams}&quot;">​</a></h2><p>에이전트 팀은 기본적으로 비활성화되어 있습니다. 셸 환경이나 <a href="/claude-code-docs-ko/settings.html">settings.json</a>에서 <code>CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS</code> 환경 변수를 <code>1</code>로 설정하여 활성화하세요:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;env&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="start-your-first-agent-team" tabindex="-1">첫 번째 에이전트 팀 시작하기 <a class="header-anchor" href="#start-your-first-agent-team" aria-label="Permalink to &quot;첫 번째 에이전트 팀 시작하기 {#start-your-first-agent-team}&quot;">​</a></h2><p>에이전트 팀을 활성화한 후, Claude에게 에이전트 팀을 만들도록 요청하고 원하는 작업과 팀 구조를 자연어로 설명하세요. Claude가 팀을 생성하고, 팀원을 생성하며, 프롬프트에 따라 작업을 조율합니다.</p><p>이 예시는 세 가지 역할이 독립적이고 서로를 기다리지 않고 문제를 탐색할 수 있기 때문에 잘 작동합니다:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CLI 도구를 설계하고 있는데, 코드베이스 전체의 TODO 주석을 추적하는 도구입니다.</span></span>
<span class="line"><span>다양한 각도에서 탐색할 에이전트 팀을 만들어주세요: 한 명은 UX,</span></span>
<span class="line"><span>한 명은 기술 아키텍처, 한 명은 반대 의견을 제시하는 역할로요.</span></span></code></pre></div><p>이후 Claude는 <a href="/claude-code-docs-ko/interactive-mode.html#task-list">공유 작업 목록</a>을 가진 팀을 만들고, 각 관점에 대한 팀원을 생성하여 문제를 탐색하게 하고, 발견 사항을 종합하며, 완료 시 <a href="#clean-up-the-team">팀을 정리</a>합니다.</p><p>리더의 터미널에는 모든 팀원과 그들이 작업 중인 내용이 나열됩니다. Shift+Down을 사용하여 팀원을 순환하고 직접 메시지를 보낼 수 있습니다. 마지막 팀원 이후 Shift+Down은 리더로 돌아갑니다.</p><p>각 팀원을 별도의 분할 창에서 보려면 <a href="#choose-a-display-mode">디스플레이 모드 선택</a>을 참조하세요.</p><h2 id="control-your-agent-team" tabindex="-1">에이전트 팀 제어하기 <a class="header-anchor" href="#control-your-agent-team" aria-label="Permalink to &quot;에이전트 팀 제어하기 {#control-your-agent-team}&quot;">​</a></h2><p>리더에게 원하는 것을 자연어로 말하세요. 리더가 지시에 따라 팀 조율, 작업 할당, 위임을 처리합니다.</p><h3 id="choose-a-display-mode" tabindex="-1">디스플레이 모드 선택 <a class="header-anchor" href="#choose-a-display-mode" aria-label="Permalink to &quot;디스플레이 모드 선택 {#choose-a-display-mode}&quot;">​</a></h3><p>에이전트 팀은 두 가지 디스플레이 모드를 지원합니다:</p><ul><li><strong>인프로세스</strong>: 모든 팀원이 메인 터미널 내에서 실행됩니다. Shift+Down으로 팀원을 순환하고 직접 메시지를 입력할 수 있습니다. 어떤 터미널에서든 작동하며 추가 설정이 필요 없습니다.</li><li><strong>분할 창</strong>: 각 팀원이 자체 창을 갖습니다. 모든 사람의 출력을 동시에 볼 수 있고, 창을 클릭하여 직접 상호작용할 수 있습니다. tmux 또는 iTerm2가 필요합니다.</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p><code>tmux</code>는 특정 운영 체제에서 알려진 제한 사항이 있으며 전통적으로 macOS에서 가장 잘 작동합니다. iTerm2에서 <code>tmux -CC</code>를 사용하는 것이 <code>tmux</code>의 권장 진입점입니다.</p></div><p>기본값은 <code>&quot;auto&quot;</code>로, 이미 tmux 세션 내에서 실행 중인 경우 분할 창을 사용하고, 그렇지 않으면 인프로세스를 사용합니다. <code>&quot;tmux&quot;</code> 설정은 분할 창 모드를 활성화하고 터미널에 따라 tmux 또는 iTerm2를 자동 감지합니다. 재정의하려면 <code>~/.claude.json</code>의 <a href="/claude-code-docs-ko/settings.html#global-config-settings">글로벌 설정</a>에서 <code>teammateMode</code>를 설정하세요:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;teammateMode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;in-process&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>단일 세션에서 인프로세스 모드를 강제하려면 플래그로 전달하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --teammate-mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> in-process</span></span></code></pre></div><p>분할 창 모드는 <a href="https://github.com/tmux/tmux/wiki" target="_blank" rel="noreferrer">tmux</a> 또는 <a href="https://github.com/mkusaka/it2" target="_blank" rel="noreferrer"><code>it2</code> CLI</a>가 설치된 iTerm2가 필요합니다. 수동 설치 방법:</p><ul><li><strong>tmux</strong>: 시스템의 패키지 관리자를 통해 설치합니다. 플랫폼별 지침은 <a href="https://github.com/tmux/tmux/wiki/Installing" target="_blank" rel="noreferrer">tmux wiki</a>를 참조하세요.</li><li><strong>iTerm2</strong>: <a href="https://github.com/mkusaka/it2" target="_blank" rel="noreferrer"><code>it2</code> CLI</a>를 설치한 다음, <strong>iTerm2 → Settings → General → Magic → Enable Python API</strong>에서 Python API를 활성화하세요.</li></ul><h3 id="specify-teammates-and-models" tabindex="-1">팀원 및 모델 지정 <a class="header-anchor" href="#specify-teammates-and-models" aria-label="Permalink to &quot;팀원 및 모델 지정 {#specify-teammates-and-models}&quot;">​</a></h3><p>Claude는 작업에 따라 생성할 팀원 수를 결정하거나, 정확히 원하는 것을 지정할 수 있습니다:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>이 모듈들을 병렬로 리팩터링할 4명의 팀원으로 팀을 만들어주세요.</span></span>
<span class="line"><span>각 팀원에게 Sonnet을 사용해주세요.</span></span></code></pre></div><h3 id="require-plan-approval-for-teammates" tabindex="-1">팀원에게 계획 승인 요구하기 <a class="header-anchor" href="#require-plan-approval-for-teammates" aria-label="Permalink to &quot;팀원에게 계획 승인 요구하기 {#require-plan-approval-for-teammates}&quot;">​</a></h3><p>복잡하거나 위험한 작업의 경우, 팀원이 구현 전에 계획을 세우도록 요구할 수 있습니다. 팀원은 리더가 접근 방식을 승인할 때까지 읽기 전용 계획 모드로 작업합니다:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>인증 모듈을 리팩터링할 아키텍트 팀원을 생성하세요.</span></span>
<span class="line"><span>변경하기 전에 계획 승인을 요구하세요.</span></span></code></pre></div><p>팀원이 계획을 완료하면 리더에게 계획 승인 요청을 보냅니다. 리더는 계획을 검토하고 승인하거나 피드백과 함께 거부합니다. 거부되면 팀원은 계획 모드를 유지하고 피드백에 따라 수정하여 다시 제출합니다. 승인되면 팀원은 계획 모드를 종료하고 구현을 시작합니다.</p><p>리더는 자율적으로 승인 결정을 내립니다. 리더의 판단에 영향을 미치려면 &quot;테스트 커버리지를 포함하는 계획만 승인&quot; 또는 &quot;데이터베이스 스키마를 수정하는 계획은 거부&quot;와 같은 기준을 프롬프트에 포함하세요.</p><h3 id="talk-to-teammates-directly" tabindex="-1">팀원에게 직접 대화하기 <a class="header-anchor" href="#talk-to-teammates-directly" aria-label="Permalink to &quot;팀원에게 직접 대화하기 {#talk-to-teammates-directly}&quot;">​</a></h3><p>각 팀원은 완전한 독립 Claude Code 세션입니다. 어떤 팀원에게든 직접 메시지를 보내 추가 지시를 하거나, 후속 질문을 하거나, 접근 방식을 변경할 수 있습니다.</p><ul><li><strong>인프로세스 모드</strong>: Shift+Down으로 팀원을 순환한 다음 메시지를 입력합니다. Enter를 눌러 팀원의 세션을 보고, Escape를 눌러 현재 턴을 중단합니다. Ctrl+T를 눌러 작업 목록을 토글합니다.</li><li><strong>분할 창 모드</strong>: 팀원의 창을 클릭하여 세션과 직접 상호작용합니다. 각 팀원은 자체 터미널의 전체 뷰를 가집니다.</li></ul><h3 id="assign-and-claim-tasks" tabindex="-1">작업 할당 및 요청 <a class="header-anchor" href="#assign-and-claim-tasks" aria-label="Permalink to &quot;작업 할당 및 요청 {#assign-and-claim-tasks}&quot;">​</a></h3><p>공유 작업 목록은 팀 전체의 작업을 조율합니다. 리더가 작업을 생성하고 팀원들이 작업을 수행합니다. 작업에는 세 가지 상태가 있습니다: 대기 중, 진행 중, 완료. 작업은 다른 작업에 의존할 수도 있습니다: 해결되지 않은 의존성이 있는 대기 중 작업은 해당 의존성이 완료될 때까지 요청할 수 없습니다.</p><p>리더가 명시적으로 작업을 할당하거나 팀원이 자체 요청할 수 있습니다:</p><ul><li><strong>리더 할당</strong>: 리더에게 어떤 작업을 어떤 팀원에게 줄지 지시합니다</li><li><strong>자체 요청</strong>: 작업을 완료한 후, 팀원이 다음 미할당, 미차단 작업을 자체적으로 선택합니다</li></ul><p>작업 요청은 파일 잠금을 사용하여 여러 팀원이 동시에 같은 작업을 요청할 때 경쟁 조건을 방지합니다.</p><h3 id="shut-down-teammates" tabindex="-1">팀원 종료 <a class="header-anchor" href="#shut-down-teammates" aria-label="Permalink to &quot;팀원 종료 {#shut-down-teammates}&quot;">​</a></h3><p>팀원의 세션을 정상적으로 종료하려면:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>연구원 팀원에게 종료를 요청하세요</span></span></code></pre></div><p>리더가 종료 요청을 보냅니다. 팀원은 승인하여 정상적으로 종료하거나 설명과 함께 거부할 수 있습니다.</p><h3 id="clean-up-the-team" tabindex="-1">팀 정리 <a class="header-anchor" href="#clean-up-the-team" aria-label="Permalink to &quot;팀 정리 {#clean-up-the-team}&quot;">​</a></h3><p>작업이 끝나면 리더에게 정리를 요청하세요:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>팀을 정리해주세요</span></span></code></pre></div><p>이렇게 하면 공유 팀 리소스가 제거됩니다. 리더가 정리를 실행할 때 활성 팀원이 있는지 확인하고, 아직 실행 중인 팀원이 있으면 실패하므로 먼저 종료하세요.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>항상 리더를 사용하여 정리하세요. 팀원이 정리를 실행하면 팀 컨텍스트가 올바르게 해결되지 않아 리소스가 일관되지 않은 상태로 남을 수 있습니다.</p></div><h3 id="enforce-quality-gates-with-hooks" tabindex="-1">훅으로 품질 게이트 적용 <a class="header-anchor" href="#enforce-quality-gates-with-hooks" aria-label="Permalink to &quot;훅으로 품질 게이트 적용 {#enforce-quality-gates-with-hooks}&quot;">​</a></h3><p><a href="/claude-code-docs-ko/hooks.html">훅</a>을 사용하여 팀원이 작업을 완료하거나 작업이 생성 또는 완료될 때 규칙을 적용할 수 있습니다:</p><ul><li><a href="/claude-code-docs-ko/hooks.html#teammateidle"><code>TeammateIdle</code></a>: 팀원이 유휴 상태가 되려고 할 때 실행됩니다. 종료 코드 2로 종료하면 피드백을 보내고 팀원이 계속 작업합니다.</li><li><a href="/claude-code-docs-ko/hooks.html#taskcreated"><code>TaskCreated</code></a>: 작업이 생성될 때 실행됩니다. 종료 코드 2로 종료하면 생성을 방지하고 피드백을 보냅니다.</li><li><a href="/claude-code-docs-ko/hooks.html#taskcompleted"><code>TaskCompleted</code></a>: 작업이 완료로 표시될 때 실행됩니다. 종료 코드 2로 종료하면 완료를 방지하고 피드백을 보냅니다.</li></ul><h2 id="how-agent-teams-work" tabindex="-1">에이전트 팀 작동 방식 <a class="header-anchor" href="#how-agent-teams-work" aria-label="Permalink to &quot;에이전트 팀 작동 방식 {#how-agent-teams-work}&quot;">​</a></h2><p>이 섹션에서는 에이전트 팀의 아키텍처와 메커니즘을 다룹니다. 사용을 시작하려면 위의 <a href="#control-your-agent-team">에이전트 팀 제어하기</a>를 참조하세요.</p><h3 id="how-claude-starts-agent-teams" tabindex="-1">Claude가 에이전트 팀을 시작하는 방법 <a class="header-anchor" href="#how-claude-starts-agent-teams" aria-label="Permalink to &quot;Claude가 에이전트 팀을 시작하는 방법 {#how-claude-starts-agent-teams}&quot;">​</a></h3><p>에이전트 팀이 시작되는 두 가지 방법이 있습니다:</p><ul><li><strong>팀을 요청하는 경우</strong>: Claude에게 병렬 작업이 유용한 작업을 주고 명시적으로 에이전트 팀을 요청합니다. Claude가 지시에 따라 팀을 생성합니다.</li><li><strong>Claude가 팀을 제안하는 경우</strong>: Claude가 작업이 병렬 작업에 적합하다고 판단하면 팀 생성을 제안할 수 있습니다. 진행하기 전에 확인을 받습니다.</li></ul><p>두 경우 모두 사용자가 제어권을 유지합니다. Claude는 승인 없이 팀을 생성하지 않습니다.</p><h3 id="architecture" tabindex="-1">아키텍처 <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;아키텍처 {#architecture}&quot;">​</a></h3><p>에이전트 팀은 다음으로 구성됩니다:</p><table tabindex="0"><thead><tr><th style="text-align:left;">구성 요소</th><th style="text-align:left;">역할</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>팀 리더</strong></td><td style="text-align:left;">팀을 생성하고, 팀원을 생성하며, 작업을 조율하는 메인 Claude Code 세션</td></tr><tr><td style="text-align:left;"><strong>팀원</strong></td><td style="text-align:left;">각각 할당된 작업을 수행하는 별도의 Claude Code 인스턴스</td></tr><tr><td style="text-align:left;"><strong>작업 목록</strong></td><td style="text-align:left;">팀원들이 요청하고 완료하는 공유 작업 항목 목록</td></tr><tr><td style="text-align:left;"><strong>메일박스</strong></td><td style="text-align:left;">에이전트 간 통신을 위한 메시징 시스템</td></tr></tbody></table><p>디스플레이 설정 옵션은 <a href="#choose-a-display-mode">디스플레이 모드 선택</a>을 참조하세요. 팀원 메시지는 자동으로 리더에게 전달됩니다.</p><p>시스템은 작업 의존성을 자동으로 관리합니다. 팀원이 다른 작업이 의존하는 작업을 완료하면, 차단된 작업이 수동 개입 없이 해제됩니다.</p><p>팀과 작업은 로컬에 저장됩니다:</p><ul><li><strong>팀 설정</strong>: <code>~/.claude/teams/{team-name}/config.json</code></li><li><strong>작업 목록</strong>: <code>~/.claude/tasks/{team-name}/</code></li></ul><p>Claude Code는 팀을 생성할 때 이 두 가지를 자동으로 생성하고, 팀원이 참여하거나 유휴 상태가 되거나 떠날 때 업데이트합니다. 팀 설정은 세션 ID와 tmux 창 ID와 같은 런타임 상태를 보유하므로, 수동으로 편집하거나 미리 작성하지 마세요: 다음 상태 업데이트 시 변경 사항이 덮어씌워집니다.</p><p>재사용 가능한 팀원 역할을 정의하려면 대신 <a href="#use-subagent-definitions-for-teammates">서브에이전트 정의 사용</a>을 참조하세요.</p><p>팀 설정에는 각 팀원의 이름, 에이전트 ID, 에이전트 유형이 포함된 <code>members</code> 배열이 있습니다. 팀원은 이 파일을 읽어 다른 팀 멤버를 확인할 수 있습니다.</p><p>팀 설정의 프로젝트 수준 등가물은 없습니다. 프로젝트 디렉토리의 <code>.claude/teams/teams.json</code>과 같은 파일은 설정으로 인식되지 않으며, Claude는 이를 일반 파일로 취급합니다.</p><h3 id="use-subagent-definitions-for-teammates" tabindex="-1">팀원에 서브에이전트 정의 사용 <a class="header-anchor" href="#use-subagent-definitions-for-teammates" aria-label="Permalink to &quot;팀원에 서브에이전트 정의 사용 {#use-subagent-definitions-for-teammates}&quot;">​</a></h3><p>팀원을 생성할 때 프로젝트, 사용자, 플러그인, CLI 정의 등 모든 <a href="/claude-code-docs-ko/sub-agents.html#choose-the-subagent-scope">서브에이전트 범위</a>의 <a href="/claude-code-docs-ko/sub-agents.html">서브에이전트</a> 유형을 참조할 수 있습니다. 이를 통해 security-reviewer나 test-runner와 같은 역할을 한 번 정의하고, 위임된 서브에이전트와 에이전트 팀 팀원 모두로 재사용할 수 있습니다.</p><p>서브에이전트 정의를 사용하려면 Claude에게 팀원을 생성하도록 요청할 때 이름으로 언급하세요:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>security-reviewer 에이전트 유형을 사용하여 인증 모듈을 감사할 팀원을 생성하세요.</span></span></code></pre></div><p>팀원은 해당 정의의 <code>tools</code> 허용 목록과 <code>model</code>을 따르며, 정의의 본문은 팀원의 시스템 프롬프트를 대체하는 것이 아니라 추가 지침으로 추가됩니다. <code>SendMessage</code>와 작업 관리 도구와 같은 팀 조율 도구는 <code>tools</code>가 다른 도구를 제한하더라도 팀원에게 항상 사용 가능합니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>서브에이전트 정의의 <code>skills</code> 및 <code>mcpServers</code> 프론트매터 필드는 해당 정의가 팀원으로 실행될 때 적용되지 않습니다. 팀원은 일반 세션과 마찬가지로 프로젝트 및 사용자 설정에서 스킬과 MCP 서버를 로드합니다.</p></div><h3 id="permissions" tabindex="-1">권한 <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;권한 {#permissions}&quot;">​</a></h3><p>팀원은 리더의 권한 설정으로 시작합니다. 리더가 <code>--dangerously-skip-permissions</code>로 실행되면 모든 팀원도 마찬가지입니다. 생성 후에는 개별 팀원 모드를 변경할 수 있지만, 생성 시 팀원별 모드를 설정할 수는 없습니다.</p><h3 id="context-and-communication" tabindex="-1">컨텍스트 및 통신 <a class="header-anchor" href="#context-and-communication" aria-label="Permalink to &quot;컨텍스트 및 통신 {#context-and-communication}&quot;">​</a></h3><p>각 팀원은 자체 컨텍스트 윈도우를 가집니다. 생성 시 팀원은 일반 세션과 동일한 프로젝트 컨텍스트를 로드합니다: CLAUDE.md, MCP 서버, 스킬. 또한 리더의 생성 프롬프트도 받습니다. 리더의 대화 기록은 이전되지 않습니다.</p><p><strong>팀원이 정보를 공유하는 방법:</strong></p><ul><li><strong>자동 메시지 전달</strong>: 팀원이 메시지를 보내면 수신자에게 자동으로 전달됩니다. 리더가 업데이트를 폴링할 필요가 없습니다.</li><li><strong>유휴 알림</strong>: 팀원이 작업을 완료하고 멈추면 자동으로 리더에게 알립니다.</li><li><strong>공유 작업 목록</strong>: 모든 에이전트가 작업 상태를 보고 사용 가능한 작업을 요청할 수 있습니다.</li></ul><p><strong>팀원 메시징:</strong></p><ul><li><strong>message</strong>: 특정 팀원 한 명에게 메시지를 보냅니다</li><li><strong>broadcast</strong>: 모든 팀원에게 동시에 보냅니다. 비용이 팀 규모에 따라 증가하므로 신중하게 사용하세요.</li></ul><p>리더는 팀원을 생성할 때 각각에게 이름을 할당하며, 어떤 팀원이든 그 이름으로 다른 팀원에게 메시지를 보낼 수 있습니다. 나중에 프롬프트에서 참조할 수 있는 예측 가능한 이름을 얻으려면, 생성 지시에서 리더에게 각 팀원을 무엇이라고 부를지 말하세요.</p><h3 id="token-usage" tabindex="-1">토큰 사용량 <a class="header-anchor" href="#token-usage" aria-label="Permalink to &quot;토큰 사용량 {#token-usage}&quot;">​</a></h3><p>에이전트 팀은 단일 세션보다 훨씬 더 많은 토큰을 사용합니다. 각 팀원은 자체 컨텍스트 윈도우를 가지며, 토큰 사용량은 활성 팀원 수에 따라 증가합니다. 연구, 리뷰, 새로운 기능 작업의 경우 추가 토큰은 대개 가치가 있습니다. 일상적인 작업의 경우 단일 세션이 더 비용 효율적입니다. 사용 가이드는 <a href="/claude-code-docs-ko/costs.html#agent-team-token-costs">에이전트 팀 토큰 비용</a>을 참조하세요.</p><h2 id="use-case-examples" tabindex="-1">사용 사례 예시 <a class="header-anchor" href="#use-case-examples" aria-label="Permalink to &quot;사용 사례 예시 {#use-case-examples}&quot;">​</a></h2><p>이 예시들은 에이전트 팀이 병렬 탐색이 가치를 더하는 작업을 어떻게 처리하는지 보여줍니다.</p><h3 id="run-a-parallel-code-review" tabindex="-1">병렬 코드 리뷰 실행 <a class="header-anchor" href="#run-a-parallel-code-review" aria-label="Permalink to &quot;병렬 코드 리뷰 실행 {#run-a-parallel-code-review}&quot;">​</a></h3><p>단일 리뷰어는 한 번에 한 유형의 이슈에 집중하는 경향이 있습니다. 리뷰 기준을 독립적인 영역으로 분할하면 보안, 성능, 테스트 커버리지가 모두 동시에 철저한 관심을 받습니다. 이 프롬프트는 각 팀원에게 겹치지 않도록 고유한 렌즈를 할당합니다:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PR #142를 리뷰할 에이전트 팀을 만들어주세요. 세 명의 리뷰어를 생성하세요:</span></span>
<span class="line"><span>- 보안 관련 사항에 집중하는 리뷰어</span></span>
<span class="line"><span>- 성능 영향을 확인하는 리뷰어</span></span>
<span class="line"><span>- 테스트 커버리지를 검증하는 리뷰어</span></span>
<span class="line"><span>각자 리뷰하고 발견 사항을 보고하도록 하세요.</span></span></code></pre></div><p>각 리뷰어는 동일한 PR에서 작업하지만 서로 다른 필터를 적용합니다. 리더는 모든 리뷰어가 완료한 후 전체 발견 사항을 종합합니다.</p><h3 id="investigate-with-competing-hypotheses" tabindex="-1">경쟁 가설로 조사 <a class="header-anchor" href="#investigate-with-competing-hypotheses" aria-label="Permalink to &quot;경쟁 가설로 조사 {#investigate-with-competing-hypotheses}&quot;">​</a></h3><p>근본 원인이 불명확할 때 단일 에이전트는 하나의 그럴듯한 설명을 찾고 탐색을 멈추는 경향이 있습니다. 이 프롬프트는 팀원을 명시적으로 적대적으로 만들어 이를 방지합니다: 각 팀원의 역할은 자신의 이론을 조사할 뿐만 아니라 다른 팀원의 이론에 이의를 제기하는 것입니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>사용자들이 앱이 연결을 유지하지 않고 한 메시지 후 종료된다고 보고합니다.</span></span>
<span class="line"><span>서로 다른 가설을 조사할 5명의 에이전트 팀원을 생성하세요. 과학적</span></span>
<span class="line"><span>토론처럼 서로의 이론을 반증하려고 대화하도록 하세요. 합의가 이루어진</span></span>
<span class="line"><span>내용으로 발견 사항 문서를 업데이트하세요.</span></span></code></pre></div><p>토론 구조가 여기서 핵심 메커니즘입니다. 순차적 조사는 앵커링의 영향을 받습니다: 하나의 이론이 탐색되면 이후 조사가 그 쪽으로 편향됩니다.</p><p>서로를 적극적으로 반증하려는 여러 독립 조사자가 있으면, 살아남은 이론이 실제 근본 원인일 가능성이 훨씬 높습니다.</p><h2 id="best-practices" tabindex="-1">모범 사례 <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;모범 사례 {#best-practices}&quot;">​</a></h2><h3 id="give-teammates-enough-context" tabindex="-1">팀원에게 충분한 컨텍스트 제공 <a class="header-anchor" href="#give-teammates-enough-context" aria-label="Permalink to &quot;팀원에게 충분한 컨텍스트 제공 {#give-teammates-enough-context}&quot;">​</a></h3><p>팀원은 CLAUDE.md, MCP 서버, 스킬을 포함한 프로젝트 컨텍스트를 자동으로 로드하지만, 리더의 대화 기록은 상속하지 않습니다. 자세한 내용은 <a href="#context-and-communication">컨텍스트 및 통신</a>을 참조하세요. 생성 프롬프트에 작업별 세부 정보를 포함하세요:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>다음 프롬프트로 보안 리뷰어 팀원을 생성하세요: &quot;src/auth/의 인증 모듈을</span></span>
<span class="line"><span>보안 취약점에 대해 리뷰하세요. 토큰 처리, 세션 관리, 입력 유효성 검사에</span></span>
<span class="line"><span>집중하세요. 앱은 httpOnly 쿠키에 저장된 JWT 토큰을 사용합니다.</span></span>
<span class="line"><span>심각도 등급과 함께 이슈를 보고하세요.&quot;</span></span></code></pre></div><h3 id="choose-an-appropriate-team-size" tabindex="-1">적절한 팀 규모 선택 <a class="header-anchor" href="#choose-an-appropriate-team-size" aria-label="Permalink to &quot;적절한 팀 규모 선택 {#choose-an-appropriate-team-size}&quot;">​</a></h3><p>팀원 수에 하드 리밋은 없지만 실질적인 제약이 있습니다:</p><ul><li><strong>토큰 비용은 선형적으로 증가</strong>: 각 팀원은 자체 컨텍스트 윈도우를 가지며 독립적으로 토큰을 소비합니다. 자세한 내용은 <a href="/claude-code-docs-ko/costs.html#agent-team-token-costs">에이전트 팀 토큰 비용</a>을 참조하세요.</li><li><strong>조율 오버헤드 증가</strong>: 팀원이 많을수록 더 많은 통신, 작업 조율, 잠재적 충돌이 발생합니다</li><li><strong>수확 체감</strong>: 특정 시점 이후 추가 팀원이 작업 속도를 비례적으로 높이지 않습니다</li></ul><p>대부분의 워크플로우에서 3-5명의 팀원으로 시작하세요. 이는 병렬 작업과 관리 가능한 조율 사이의 균형을 맞춥니다. 이 가이드의 예시는 다양한 작업 유형에서 잘 작동하는 3-5명의 팀원을 사용합니다.</p><p>팀원당 5-6개의 <a href="/claude-code-docs-ko/agent-teams.html#architecture">작업</a>이 있으면 과도한 컨텍스트 전환 없이 모두가 생산적으로 유지됩니다. 15개의 독립적인 작업이 있다면 3명의 팀원이 좋은 출발점입니다.</p><p>작업이 팀원들의 동시 작업으로 진정한 이점을 얻을 때만 규모를 확장하세요. 집중된 3명의 팀원이 분산된 5명보다 더 나은 성과를 내는 경우가 많습니다.</p><h3 id="size-tasks-appropriately" tabindex="-1">작업 크기를 적절하게 설정 <a class="header-anchor" href="#size-tasks-appropriately" aria-label="Permalink to &quot;작업 크기를 적절하게 설정 {#size-tasks-appropriately}&quot;">​</a></h3><ul><li><strong>너무 작은 경우</strong>: 조율 오버헤드가 이점을 초과합니다</li><li><strong>너무 큰 경우</strong>: 팀원이 너무 오래 체크인 없이 작업하여 낭비된 노력의 위험이 증가합니다</li><li><strong>적절한 경우</strong>: 함수, 테스트 파일, 리뷰와 같은 명확한 결과물을 생성하는 자체 완결 단위</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>리더는 자동으로 작업을 분할하고 팀원에게 할당합니다. 충분한 작업을 생성하지 않는 경우, 작업을 더 작은 조각으로 나누도록 요청하세요. 팀원당 5-6개의 작업이 있으면 모두가 생산적으로 유지되고 누군가 막혔을 때 리더가 작업을 재할당할 수 있습니다.</p></div><h3 id="wait-for-teammates-to-finish" tabindex="-1">팀원이 완료할 때까지 대기 <a class="header-anchor" href="#wait-for-teammates-to-finish" aria-label="Permalink to &quot;팀원이 완료할 때까지 대기 {#wait-for-teammates-to-finish}&quot;">​</a></h3><p>가끔 리더가 팀원을 기다리지 않고 직접 작업을 구현하기 시작합니다. 이를 발견하면:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>진행하기 전에 팀원들이 작업을 완료할 때까지 기다리세요</span></span></code></pre></div><h3 id="start-with-research-and-review" tabindex="-1">연구와 리뷰로 시작 <a class="header-anchor" href="#start-with-research-and-review" aria-label="Permalink to &quot;연구와 리뷰로 시작 {#start-with-research-and-review}&quot;">​</a></h3><p>에이전트 팀이 처음이라면 명확한 경계가 있고 코드 작성이 필요 없는 작업으로 시작하세요: PR 리뷰, 라이브러리 조사, 버그 조사. 이러한 작업은 병렬 구현에 따르는 조율 문제 없이 병렬 탐색의 가치를 보여줍니다.</p><h3 id="avoid-file-conflicts" tabindex="-1">파일 충돌 방지 <a class="header-anchor" href="#avoid-file-conflicts" aria-label="Permalink to &quot;파일 충돌 방지 {#avoid-file-conflicts}&quot;">​</a></h3><p>두 팀원이 같은 파일을 편집하면 덮어쓰기가 발생합니다. 각 팀원이 서로 다른 파일 세트를 소유하도록 작업을 분할하세요.</p><h3 id="monitor-and-steer" tabindex="-1">모니터링 및 방향 조정 <a class="header-anchor" href="#monitor-and-steer" aria-label="Permalink to &quot;모니터링 및 방향 조정 {#monitor-and-steer}&quot;">​</a></h3><p>팀원의 진행 상황을 확인하고, 효과가 없는 접근 방식을 재조정하며, 발견 사항을 수시로 종합하세요. 팀을 너무 오래 무인 상태로 두면 낭비되는 노력의 위험이 증가합니다.</p><h2 id="troubleshooting" tabindex="-1">문제 해결 <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;문제 해결 {#troubleshooting}&quot;">​</a></h2><h3 id="teammates-not-appearing" tabindex="-1">팀원이 나타나지 않는 경우 <a class="header-anchor" href="#teammates-not-appearing" aria-label="Permalink to &quot;팀원이 나타나지 않는 경우 {#teammates-not-appearing}&quot;">​</a></h3><p>Claude에게 팀을 만들도록 요청한 후 팀원이 나타나지 않는 경우:</p><ul><li>인프로세스 모드에서는 팀원이 이미 실행 중이지만 보이지 않을 수 있습니다. Shift+Down을 눌러 활성 팀원을 순환하세요.</li><li>Claude에게 준 작업이 팀을 구성할 만큼 충분히 복잡한지 확인하세요. Claude는 작업에 따라 팀원 생성 여부를 결정합니다.</li><li>분할 창을 명시적으로 요청한 경우, tmux가 설치되어 있고 PATH에서 사용 가능한지 확인하세요:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">which</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tmux</span></span></code></pre></div></li><li>iTerm2의 경우, <code>it2</code> CLI가 설치되어 있고 iTerm2 환경설정에서 Python API가 활성화되어 있는지 확인하세요.</li></ul><h3 id="too-many-permission-prompts" tabindex="-1">너무 많은 권한 프롬프트 <a class="header-anchor" href="#too-many-permission-prompts" aria-label="Permalink to &quot;너무 많은 권한 프롬프트 {#too-many-permission-prompts}&quot;">​</a></h3><p>팀원의 권한 요청이 리더에게 전달되어 마찰이 발생할 수 있습니다. 팀원을 생성하기 전에 <a href="/claude-code-docs-ko/permissions.html">권한 설정</a>에서 일반적인 작업을 사전 승인하여 중단을 줄이세요.</p><h3 id="teammates-stopping-on-errors" tabindex="-1">팀원이 오류 시 중단되는 경우 <a class="header-anchor" href="#teammates-stopping-on-errors" aria-label="Permalink to &quot;팀원이 오류 시 중단되는 경우 {#teammates-stopping-on-errors}&quot;">​</a></h3><p>팀원이 오류를 만난 후 복구하지 않고 중단할 수 있습니다. 인프로세스 모드에서 Shift+Down을 사용하거나 분할 모드에서 창을 클릭하여 출력을 확인한 다음:</p><ul><li>직접 추가 지시를 내리거나</li><li>작업을 계속할 대체 팀원을 생성하세요</li></ul><h3 id="lead-shuts-down-before-work-is-done" tabindex="-1">작업이 완료되기 전에 리더가 종료되는 경우 <a class="header-anchor" href="#lead-shuts-down-before-work-is-done" aria-label="Permalink to &quot;작업이 완료되기 전에 리더가 종료되는 경우 {#lead-shuts-down-before-work-is-done}&quot;">​</a></h3><p>리더가 모든 작업이 실제로 완료되기 전에 팀이 끝났다고 판단할 수 있습니다. 이런 경우 계속 진행하도록 지시하세요. 리더가 위임하는 대신 직접 작업을 시작하면 팀원이 완료할 때까지 기다리도록 지시할 수도 있습니다.</p><h3 id="orphaned-tmux-sessions" tabindex="-1">고아 tmux 세션 <a class="header-anchor" href="#orphaned-tmux-sessions" aria-label="Permalink to &quot;고아 tmux 세션 {#orphaned-tmux-sessions}&quot;">​</a></h3><p>팀이 종료된 후 tmux 세션이 유지되면 완전히 정리되지 않은 것일 수 있습니다. 세션을 나열하고 팀이 생성한 세션을 종료하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kill-session</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">session-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><h2 id="limitations" tabindex="-1">제한 사항 <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;제한 사항 {#limitations}&quot;">​</a></h2><p>에이전트 팀은 실험적 기능입니다. 알아야 할 현재 제한 사항:</p><ul><li><strong>인프로세스 팀원의 세션 재개 불가</strong>: <code>/resume</code> 및 <code>/rewind</code>는 인프로세스 팀원을 복원하지 않습니다. 세션을 재개한 후 리더가 더 이상 존재하지 않는 팀원에게 메시지를 보내려고 할 수 있습니다. 이런 경우 리더에게 새 팀원을 생성하도록 지시하세요.</li><li><strong>작업 상태가 지연될 수 있음</strong>: 팀원이 가끔 작업을 완료로 표시하지 못하여 의존 작업이 차단됩니다. 작업이 멈춘 것처럼 보이면 실제로 작업이 완료되었는지 확인하고 수동으로 작업 상태를 업데이트하거나 리더에게 팀원을 독촉하도록 지시하세요.</li><li><strong>종료가 느릴 수 있음</strong>: 팀원은 종료하기 전에 현재 요청이나 도구 호출을 완료하며, 이는 시간이 걸릴 수 있습니다.</li><li><strong>세션당 하나의 팀</strong>: 리더는 한 번에 하나의 팀만 관리할 수 있습니다. 새 팀을 시작하기 전에 현재 팀을 정리하세요.</li><li><strong>중첩 팀 불가</strong>: 팀원은 자체 팀이나 팀원을 생성할 수 없습니다. 리더만 팀을 관리할 수 있습니다.</li><li><strong>리더 고정</strong>: 팀을 생성한 세션이 수명 동안 리더입니다. 팀원을 리더로 승격하거나 리더십을 이전할 수 없습니다.</li><li><strong>생성 시 권한 설정</strong>: 모든 팀원은 리더의 권한 모드로 시작합니다. 생성 후 개별 팀원 모드를 변경할 수 있지만, 생성 시 팀원별 모드를 설정할 수는 없습니다.</li><li><strong>분할 창은 tmux 또는 iTerm2 필요</strong>: 기본 인프로세스 모드는 모든 터미널에서 작동합니다. 분할 창 모드는 VS Code의 통합 터미널, Windows Terminal, Ghostty에서 지원되지 않습니다.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong><code>CLAUDE.md</code>는 정상적으로 작동합니다</strong>: 팀원은 작업 디렉토리에서 <code>CLAUDE.md</code> 파일을 읽습니다. 이를 사용하여 모든 팀원에게 프로젝트별 가이드를 제공하세요.</p></div><h2 id="next-steps" tabindex="-1">다음 단계 <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;다음 단계 {#next-steps}&quot;">​</a></h2><p>병렬 작업 및 위임을 위한 관련 접근 방식을 살펴보세요:</p><ul><li><strong>경량 위임</strong>: <a href="/claude-code-docs-ko/sub-agents.html">서브에이전트</a>는 세션 내에서 연구 또는 검증을 위한 헬퍼 에이전트를 생성하며, 에이전트 간 조율이 필요 없는 작업에 적합합니다</li><li><strong>수동 병렬 세션</strong>: <a href="/claude-code-docs-ko/common-workflows.html#run-parallel-claude-code-sessions-with-git-worktrees">Git 워크트리</a>를 사용하면 자동화된 팀 조율 없이 직접 여러 Claude Code 세션을 실행할 수 있습니다</li><li><strong>접근 방식 비교</strong>: <a href="/claude-code-docs-ko/features-overview.html#compare-similar-features">서브에이전트 vs 에이전트 팀</a> 비교에서 나란히 비교를 확인하세요</li></ul>`,154)])])}const g=e(o,[["render",n]]);export{u as __pageData,g as default};
